import React from 'react';
import BuildingNotFound from './building-not-found';
import AgeContainer from './data-containers/age';
import CommunityContainer from './data-containers/community';
import ConstructionContainer from './data-containers/construction';
import DynamicsContainer from './data-containers/dynamics';
import LocationContainer from './data-containers/location';
import PlanningContainer from './data-containers/planning';
import SizeContainer from './data-containers/size';
import StreetscapeContainer from './data-containers/streetscape';
import SustainabilityContainer from './data-containers/sustainability';
import TeamContainer from './data-containers/team';
import TypeContainer from './data-containers/type';
import UseContainer from './data-containers/use';
/**
 * Top-level container for building view/edit form
 *
 * @param props
 */
const BuildingView = (props) => {
    switch (props.cat) {
        case 'location':
            return React.createElement(LocationContainer, Object.assign({}, props, { title: "Mapping", help: "https://pages.colouring.bh/location", intro: "Where are the buildings? Address, location and cross-references." }));
        case 'use':
            return React.createElement(UseContainer, Object.assign({}, props, { inactive: false, title: "Land Use", intro: "How are buildings used, and how does use change over time? Coming soon\u2026", help: "https://pages.colouring.bh/use" }));
        case 'type':
            return React.createElement(TypeContainer, Object.assign({}, props, { inactive: false, title: "Commerce & Activity", intro: "How are buildings used and what kinds of activity does each building support?", help: "https://www.pages.colouring.bh/buildingtypology" }));
        case 'age':
            return React.createElement(AgeContainer, Object.assign({}, props, { title: "Age & History", help: "https://pages.colouring.bh/age", intro: "Building age data can support energy analysis and help predict long-term change." }));
        case 'size':
            return React.createElement(SizeContainer, Object.assign({}, props, { title: "Morphology", intro: "How big are buildings?", help: "https://pages.colouring.bh/shapeandsize" }));
        case 'construction':
            return React.createElement(ConstructionContainer, Object.assign({}, props, { title: "Construction & Design", intro: "How are buildings built?", help: "https://pages.colouring.bh/construction" }));
        case 'team':
            return React.createElement(TeamContainer, Object.assign({}, props, { title: "Investment & Engagement", intro: "Who built the buildings? Coming soon\u2026", help: "https://pages.colouring.bh/team", inactive: true }));
        case 'sustainability':
            return React.createElement(SustainabilityContainer, Object.assign({}, props, { title: "Assessment", intro: "Are buildings energy efficient?", help: "https://pages.colouring.bh/sustainability", inactive: false }));
        case 'streetscape':
            return React.createElement(StreetscapeContainer, Object.assign({}, props, { title: "Green / Urban Infrastructure", intro: "What's the building's context? Coming soon\u2026", help: "https://pages.colouring.bh/streetscape", inactive: true }));
        case 'community':
            return React.createElement(CommunityContainer, Object.assign({}, props, { title: "Social", intro: "How does this building work for the local community?", help: "https://pages.colouring.bh/community" }));
        case 'planning':
            return React.createElement(PlanningContainer, Object.assign({}, props, { title: "Conservation", intro: "Planning controls relating to protection and reuse.", help: "https://pages.colouring.bh/planning" }));
        case 'dynamics':
            return React.createElement(DynamicsContainer, Object.assign({}, props, { title: "Disaster Management", intro: "How has the site of this building changed over time?", help: "https://pages.colouring.bh/buildingcategories", inactive: true }));
        default:
            return React.createElement(BuildingNotFound, { mode: "view" });
    }
};
export default BuildingView;
